import os, sys, json, argparse, math
import numpy as np
import torch
from collections import deque

from cogniplan_env import ExplorationEnv
from model import QNetwork
from utils import preprocess_obs


def euclidean(p1, p2):
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def build_graph(nodes):
    """Build adjacency list and coordinate-to-index mapping from the environment's node graph."""
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = (n['coords'][0], n['coords'][1])
        coord_to_idx[coord] = i
    adj = [[] for _ in nodes]
    for i, n in enumerate(nodes):
        for nb_coord in n['neighbors']:
            nb_key = (nb_coord[0], nb_coord[1])
            if nb_key in coord_to_idx:
                adj[i].append(coord_to_idx[nb_key])
    return coord_to_idx, adj


def bfs_path(start_coord, target_coord, coord_to_idx, adj, nodes):
    """Return list of node coords from start_coord to target_coord (excluding start)."""
    if start_coord == target_coord:
        return []
    start_idx = coord_to_idx.get(start_coord)
    target_idx = coord_to_idx.get(target_coord)
    if start_idx is None or target_idx is None:
        return None
    parent = [-1] * len(nodes)
    visited = [False] * len(nodes)
    q = deque([start_idx])
    visited[start_idx] = True
    while q:
        u = q.popleft()
        if u == target_idx:
            path = []
            while u != start_idx:
                path.append(u)
                u = parent[u]
            path.reverse()
            return [nodes[i]['coords'] for i in path]
        for v in adj[u]:
            if not visited[v]:
                visited[v] = True
                parent[v] = u
                q.append(v)
    return None


def heuristic_policy(obs):
    """Original utility-greedy neighbour selection."""
    neighbors = obs["neighbors"]
    nodes = obs["nodes"]
    if not neighbors:
        return None
    best = None
    best_util = -1
    neighbor_set = set(tuple(nb) for nb in neighbors)
    for n in nodes:
        coord = tuple(n["coords"])
        if coord in neighbor_set:
            if n["utility"] > best_util:
                best_util = n["utility"]
                best = coord
    if best is None:
        best = tuple(neighbors[0])
    return best


def improved_policy(obs, current_node_coord, coord_to_idx, adj, nodes):
    """Frontier-based policy using graph pathfinding."""
    neighbors = obs.get('neighbors', [])
    if not neighbors:
        return None
    neighbor_set = set(tuple(nb) for nb in neighbors)
    # 1. Prefer high-utility immediate neighbour.
    best_util_neighbor = None
    best_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in neighbor_set:
            if n['utility'] > best_util:
                best_util = n['utility']
                best_util_neighbor = coord
    if best_util > 0:
        return best_util_neighbor

    # 2. No useful neighbour → plan to the nearest frontier.
    frontiers = obs.get('frontiers', [])
    if not frontiers:
        return None
    # Find closest frontier to current position
    closest_frontier = None
    min_f_dist = float('inf')
    for f in frontiers:
        d = euclidean(current_node_coord, f)
        if d < min_f_dist:
            min_f_dist = d
            closest_frontier = f
    if closest_frontier is None:
        return None

    # Find the graph node closest to that frontier
    target_node_coord = None
    min_node_dist = float('inf')
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        d = euclidean(coord, closest_frontier)
        if d < min_node_dist:
            min_node_dist = d
            target_node_coord = coord
    if target_node_coord is None:
        return None

    # Plan path from current node to frontier's nearest node
    path = bfs_path(current_node_coord, target_node_coord, coord_to_idx, adj, nodes)
    if path and len(path) > 0:
        next_node = path[0]
        if next_node in neighbor_set:
            return next_node

    # 3. Fallback: any neighbour
    return tuple(neighbors[0])


def model_policy(obs, q_net, device):
    neighbors = obs["neighbors"]
    if not neighbors:
        return None
    state_map, nb_coords, nb_utility = preprocess_obs(obs)
    map_b = state_map.unsqueeze(0).to(device)
    nb_b = nb_coords.unsqueeze(0).to(device)
    util_b = nb_utility.unsqueeze(0).to(device)
    with torch.no_grad():
        q_vals = q_net(map_b, nb_b, util_b).squeeze(0)
        best_idx = q_vals.argmax().item()
    return neighbors[best_idx]


def run_episode_model(env, q_net, device):
    obs = env.reset()
    done = False
    for step in range(128):
        target = model_policy(obs, q_net, device)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def run_episode_improved(env):
    obs = env.reset()
    nodes = obs['nodes']
    coord_to_idx, adj = build_graph(nodes)

    # Align to closest free node at start
    robot_pos = obs['robot_pos']
    start_coord = None
    min_d = float('inf')
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        d = euclidean((robot_pos[0], robot_pos[1]), coord)
        if d < min_d:
            min_d = d
            start_coord = coord
    current_node = start_coord

    for step in range(128):
        target = improved_policy(obs, current_node, coord_to_idx, adj, nodes)
        if target is None:
            break
        obs, info = env.step(target)
        current_node = target
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    # Force improved heuristic for this iteration (DQN not functional)
    use_model = False
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    q_net = None
    if use_model:
        ckpt_path = os.path.join(args.checkpoint, 'model.pt')
        if os.path.exists(ckpt_path):
            q_net = QNetwork(feature_dim=256).to(device)
            q_net.load_state_dict(torch.load(ckpt_path, map_location=device))
            q_net.eval()
            use_model = True
        else:
            use_model = False
            print('No model checkpoint, using improved heuristic.')

    config_path = os.path.join(args.data_path, 'eval_config.json')
    config = {}
    if os.path.exists(config_path):
        with open(config_path) as f:
            config = json.load(f)

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    results = {"per_episode": [], "per_type": {}}
    type_stats = {}

    for env_type in ["room", "tunnel", "outdoor"]:
        type_dir = os.path.join(maps_dir, env_type)
        if not os.path.isdir(type_dir):
            continue
        type_stats[env_type] = {
            "explored_rate_sum": 0.0,
            "travel_distance_sum": 0.0,
            "success_count": 0,
            "total": 0
        }
        for fname in sorted(os.listdir(type_dir)):
            if not fname.endswith('.png'):
                continue
            map_path = os.path.join(type_dir, fname)
            env = ExplorationEnv(map_path=map_path)
            try:
                if use_model:
                    metrics = run_episode_model(env, q_net, device)
                else:
                    metrics = run_episode_improved(env)
            except Exception as e:
                print(f"Error on {map_path}: {e}", flush=True)
                metrics = {"explored_rate": 0.0, "travel_distance": 0.0, "success": False}
            success = 1 if metrics["success"] else 0
            ep_result = {
                "map_path": os.path.join(env_type, fname),
                "env_type": env_type,
                "success": success,
                "travel_distance": float(metrics["travel_distance"]),
                "explored_rate": float(metrics["explored_rate"])
            }
            results["per_episode"].append(ep_result)
            type_stats[env_type]["explored_rate_sum"] += metrics["explored_rate"]
            if success:
                type_stats[env_type]["travel_distance_sum"] += metrics["travel_distance"]
                type_stats[env_type]["success_count"] += 1
            type_stats[env_type]["total"] += 1
            del env

    total_eps = len(results["per_episode"])
    total_explored = sum(e["explored_rate"] for e in results["per_episode"])
    total_success = sum(e["success"] for e in results["per_episode"])
    successful_eps = [e for e in results["per_episode"] if e["success"]]
    avg_travel = (
        sum(e["travel_distance"] for e in successful_eps) / len(successful_eps)
        if successful_eps else 0.0
    )

    results["explored_rate"] = total_explored / total_eps if total_eps else 0.0
    results["travel_distance"] = avg_travel
    results["success_rate"] = total_success / total_eps if total_eps else 0.0
    results["total_episodes"] = total_eps

    for env_type, stats in type_stats.items():
        cnt = stats["total"]
        avg_expl = stats["explored_rate_sum"] / cnt if cnt else 0.0
        avg_dist = (
            stats["travel_distance_sum"] / stats["success_count"]
            if stats["success_count"] > 0 else 0.0
        )
        succ_rate = stats["success_count"] / cnt if cnt else 0.0
        results["per_type"][env_type] = {
            "explored_rate": avg_expl,
            "travel_distance": avg_dist,
            "success_rate": succ_rate
        }

    with open(args.output, 'w') as f:
        json.dump(results, f, indent=2)
    print(f"Results saved to {args.output}")


if __name__ == '__main__':
    main()
